/**
 * @file environment.ts
 * @description Environment detection utilities with extension support.
 * @layer Utils
 *
 * Addresses audit finding C2: environment detection now correctly identifies
 * Chrome extension service workers and content scripts.
 */

/** Environment type — now includes 'extension' for browser extensions (MV3) */
export type Environment = 'browser' | 'node' | 'extension' | 'unknown';

/**
 * Detect the current runtime environment.
 *
 * Detection order matters:
 * 1. Chrome/browser extension (service worker or content script)
 * 2. Standard browser (window + document)
 * 3. Node.js
 * 4. Unknown
 */
export function detectEnvironment(): Environment {
  // Chrome extension (MV3 service worker or background page)
  if (
    typeof globalThis !== 'undefined' &&
    typeof (globalThis as Record<string, unknown>)['chrome'] !== 'undefined'
  ) {
    const chrome = (globalThis as Record<string, unknown>)['chrome'] as Record<string, unknown> | undefined;
    if (chrome && typeof chrome['runtime'] === 'object' && chrome['runtime'] !== null) {
      const runtime = chrome['runtime'] as Record<string, unknown>;
      if (typeof runtime['id'] === 'string') {
        return 'extension';
      }
    }
  }

  // Standard browser
  if (
    typeof (globalThis as Record<string, unknown>)['window'] !== 'undefined' &&
    typeof (globalThis as Record<string, unknown>)['document'] !== 'undefined'
  ) {
    return 'browser';
  }

  // Node.js
  if (
    typeof (globalThis as Record<string, unknown>)['process'] !== 'undefined' &&
    ((globalThis as Record<string, unknown>)['process'] as Record<string, unknown>)?.['versions'] != null &&
    (((globalThis as Record<string, unknown>)['process'] as Record<string, unknown>)?.['versions'] as Record<string, unknown>)?.['node'] != null
  ) {
    return 'node';
  }

  return 'unknown';
}

/** Current environment (cached) */
export const ENVIRONMENT = detectEnvironment();

/** Check if running in browser */
export const IS_BROWSER = ENVIRONMENT === 'browser';

/** Check if running in Node.js */
export const IS_NODE = ENVIRONMENT === 'node';

/** Check if running in a browser extension */
export const IS_EXTENSION = ENVIRONMENT === 'extension';

/** Check if running in a browser-like environment (browser or extension) */
export const IS_BROWSER_LIKE = IS_BROWSER || IS_EXTENSION;

/** Features that are only available in browser environment */
export const BROWSER_ONLY_FEATURES = [
  'calls.getLocalStream',
  'calls.getRemoteStream',
  'conference.getParticipantStream',
  'conference.startScreenShare',
  'voicemail.download',
  'profile.updateAvatar',
] as const;

/** Features that work in all environments (isomorphic) */
export const ISOMORPHIC_FEATURES = [
  'auth.*',
  'profile.*',
  'messages.*',
  'calls.start',
  'calls.answer',
  'calls.decline',
  'calls.end',
  'calls.mute',
  'calls.unmute',
  'calls.getHistory',
  'voicemail.getAll',
  'voicemail.get',
  'voicemail.markAsRead',
  'voicemail.transcribe',
  'conference.create',
  'conference.join',
  'conference.leave',
  'conference.getParticipants',
  'partyLines.*',
  'registry.*',
] as const;

/** Assert that code is running in browser environment */
export function assertBrowser(feature: string): void {
  if (!IS_BROWSER && !IS_EXTENSION) {
    throw new Error(
      `[Dial SDK] The feature "${feature}" is only available in browser/extension environments. ` +
      `It requires browser-specific APIs (MediaStream, WebRTC, etc.) that are not available in Node.js.`
    );
  }
}

/** Assert that code is running in Node.js environment */
export function assertNode(feature: string): void {
  if (!IS_NODE) {
    throw new Error(
      `[Dial SDK] The feature "${feature}" is only available in Node.js environments.`
    );
  }
}

/** Get a cross-platform fetch implementation */
export function getFetch(): typeof fetch {
  if (typeof globalThis.fetch !== 'undefined') {
    return globalThis.fetch.bind(globalThis);
  }

  throw new Error(
    '[Dial SDK] No fetch implementation found. ' +
    'Please use Node.js 18+ or provide a custom fetch implementation.'
  );
}

/** Log a warning about browser-only feature usage */
export function warnBrowserOnly(feature: string): void {
  if (!IS_BROWSER && !IS_EXTENSION) {
    console.warn(
      `[Dial SDK] Warning: "${feature}" has limited functionality in non-browser environments.`
    );
  }
}
