/**
 * @file client.ts
 * @description Client configuration types and constants.
 * @layer Types
 */

import type { Network } from './common';
import type { IDialStorage } from '../interfaces/storage';

/** SDK version */
export const SDK_VERSION = '0.3.0';

/** Default API base URLs */
export const API_BASE_URLS: Record<Network, string> = {
  mainnet: 'https://dial.wtf/api',
  alpha: 'https://alpha.dial.wtf/api',
  staging: 'https://staging.dial.wtf/api',
  testnet: 'https://testnet.dial.wtf/api',
  devnet: 'https://dev.dial.wtf/api',
};

/** Default network */
export const DEFAULT_NETWORK: Network = 'alpha';

/** Client configuration */
export interface DialClientConfig {
  /** API key for authentication */
  apiKey?: string;
  /** Network to connect to (default: alpha) */
  network?: Network;
  /** Custom API base URL (overrides network) */
  baseUrl?: string;
  /** Request timeout in milliseconds */
  timeout?: number;
  /** Enable debug logging */
  debug?: boolean;
  /** Custom fetch implementation */
  fetch?: typeof fetch;
  /** Custom storage implementation (for extension/non-browser environments) */
  storage?: IDialStorage;
}

/** Resolved client configuration with defaults */
export interface ResolvedClientConfig {
  apiKey: string | undefined;
  baseUrl: string;
  timeout: number;
  debug: boolean;
  fetch: typeof fetch;
  storage?: IDialStorage;
}

/** HTTP method types */
export type HttpMethod = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';

/** Request options */
export interface RequestOptions {
  method?: HttpMethod;
  headers?: Record<string, string>;
  body?: unknown;
  timeout?: number;
  signal?: AbortSignal;
}
